import { useEffect, useState } from 'react'
import { Search } from 'lucide-react'
import { toast } from 'sonner'
import { AppSidebar } from '@/components/app-sidebar'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import {
  AlertDialog,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog'
import { adminApi } from '@/api/admin'
import type { PaginationMeta } from '@/api/admin'
import type { AdminUser } from '@/types/auth'
import { getApiError } from '@/lib/utils'

export function UsersPage() {
  const [users, setUsers] = useState<AdminUser[]>([])
  const [meta, setMeta] = useState<PaginationMeta | null>(null)
  const [page, setPage] = useState(1)
  const [search, setSearch] = useState('')
  const [debouncedSearch, setDebouncedSearch] = useState('')
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [actionInProgress, setActionInProgress] = useState<string | null>(null)
  const [pendingDeactivate, setPendingDeactivate] = useState<AdminUser | null>(null)
  const [deactivateError, setDeactivateError] = useState<string | null>(null)

  useEffect(() => {
    const t = setTimeout(() => {
      setDebouncedSearch(search)
      setPage(1)
    }, 300)
    return () => clearTimeout(t)
  }, [search])

  function loadUsers(p = page, s = debouncedSearch) {
    setLoading(true)
    setError(null)
    adminApi
      .listUsers(p, 20, s)
      .then(({ data }) => {
        setUsers(data.users)
        setMeta(data.meta)
      })
      .catch((err: unknown) => setError(getApiError(err, 'Failed to load users. Check your connection and try again.')))
      .finally(() => setLoading(false))
  }

  useEffect(() => {
    loadUsers(page, debouncedSearch)
  }, [page, debouncedSearch])

  async function handleDeactivate(user: AdminUser) {
    setActionInProgress(user.id)
    setDeactivateError(null)
    try {
      const { data } = await adminApi.deactivateUser(user.id)
      setUsers((prev) => prev.map((u) => (u.id === user.id ? data.user : u)))
      toast.success(`${user.email} deactivated`)
      setPendingDeactivate(null)
    } catch (err: unknown) {
      setDeactivateError(getApiError(err, 'Failed to deactivate user'))
    } finally {
      setActionInProgress(null)
    }
  }

  async function handleActivate(user: AdminUser) {
    setActionInProgress(user.id)
    try {
      const { data } = await adminApi.activateUser(user.id)
      setUsers((prev) => prev.map((u) => (u.id === user.id ? data.user : u)))
      toast.success(`${user.email} activated`)
    } catch (err: unknown) {
      toast.error(getApiError(err, 'Failed to activate user'))
    } finally {
      setActionInProgress(null)
    }
  }

  return (
    <AppSidebar>
      <div className="space-y-6">
        <div className="flex items-start justify-between">
          <div>
            <h2 className="text-2xl font-bold tracking-tight">Users</h2>
            <p className="text-muted-foreground">Manage platform user accounts</p>
          </div>
          <div className="relative w-64">
            <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" aria-hidden="true" />
            <Input
              type="search"
              placeholder="Search by email..."
              className="pl-8"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              aria-label="Search users"
            />
          </div>
        </div>

        {loading ? (
          <div aria-live="polite" className="flex items-center gap-2 text-sm text-muted-foreground">
            <svg
              className="h-4 w-4 animate-spin"
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 24 24"
              aria-hidden="true"
            >
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
              <path
                className="opacity-75"
                fill="currentColor"
                d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"
              />
            </svg>
            Loading users...
          </div>
        ) : error ? (
          <div className="flex items-center justify-between rounded-md border border-destructive/30 bg-destructive/10 px-4 py-3 text-sm text-destructive">
            <span>{error}</span>
            <Button size="sm" variant="outline" onClick={() => loadUsers(page)}>
              Retry
            </Button>
          </div>
        ) : (
          <div className="rounded-md border">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b bg-muted/50">
                  <th scope="col" className="px-4 py-3 text-left font-medium">Email</th>
                  <th scope="col" className="px-4 py-3 text-left font-medium">Role</th>
                  <th scope="col" className="px-4 py-3 text-left font-medium">Verified</th>
                  <th scope="col" className="px-4 py-3 text-left font-medium">Status</th>
                  <th scope="col" className="px-4 py-3 text-left font-medium">Created</th>
                  <th scope="col" className="px-4 py-3 text-left font-medium">Actions</th>
                </tr>
              </thead>
              <tbody>
                {users.length === 0 ? (
                  <tr>
                    <td colSpan={6} className="px-4 py-10 text-center text-muted-foreground">
                      <p className="font-medium">{search ? 'No users match your search' : 'No users found'}</p>
                      <p className="text-xs mt-1">
                        {search ? 'Try a different search term.' : 'Registered users will appear here.'}
                      </p>
                    </td>
                  </tr>
                ) : (
                  users.map((user) => (
                    <tr key={user.id} className="border-b last:border-0 hover:bg-muted/25">
                      <td className="px-4 py-3 font-mono text-xs">{user.email}</td>
                      <td className="px-4 py-3">
                        <span
                          className={`inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ${
                            user.role === 'admin'
                              ? 'bg-purple-100 text-purple-800'
                              : 'bg-gray-100 text-gray-700'
                          }`}
                        >
                          {user.role}
                        </span>
                      </td>
                      <td className="px-4 py-3">
                        <span
                          className={`inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ${
                            user.email_verified
                              ? 'bg-green-100 text-green-800'
                              : 'bg-yellow-100 text-yellow-800'
                          }`}
                        >
                          {user.email_verified ? 'Verified' : 'Unverified'}
                        </span>
                      </td>
                      <td className="px-4 py-3">
                        <span
                          className={`inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ${
                            user.deactivated
                              ? 'bg-red-100 text-red-800'
                              : 'bg-green-100 text-green-800'
                          }`}
                        >
                          {user.deactivated ? 'Deactivated' : 'Active'}
                        </span>
                      </td>
                      <td className="px-4 py-3 text-muted-foreground">
                        {new Date(user.created_at).toLocaleDateString('en-CA')}
                      </td>
                      <td className="px-4 py-3">
                        {user.deactivated ? (
                          <Button
                            size="sm"
                            variant="outline"
                            disabled={actionInProgress === user.id}
                            aria-label={`Activate ${user.email}`}
                            onClick={() => handleActivate(user)}
                          >
                            {actionInProgress === user.id ? (
                              <svg className="h-3 w-3 animate-spin" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" aria-hidden="true">
                                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                              </svg>
                            ) : 'Activate'}
                          </Button>
                        ) : (
                          <Button
                            size="sm"
                            variant="outline"
                            className="text-red-600 hover:text-red-700 hover:bg-red-50"
                            disabled={actionInProgress === user.id}
                            aria-label={`Deactivate ${user.email}`}
                            onClick={() => setPendingDeactivate(user)}
                          >
                            Deactivate
                          </Button>
                        )}
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        )}

        {meta && !loading && !error && meta.total > meta.per_page && (
          <div className="flex items-center justify-between text-sm text-muted-foreground">
            <span>
              {((meta.page - 1) * meta.per_page) + 1}–{Math.min(meta.page * meta.per_page, meta.total)} of {meta.total} users
            </span>
            <div className="flex items-center gap-2">
              <Button
                size="sm"
                variant="outline"
                disabled={meta.page <= 1}
                onClick={() => setPage((p) => p - 1)}
              >
                Previous
              </Button>
              <span className="tabular-nums">
                Page {meta.page} of {Math.ceil(meta.total / meta.per_page)}
              </span>
              <Button
                size="sm"
                variant="outline"
                disabled={meta.page >= Math.ceil(meta.total / meta.per_page)}
                onClick={() => setPage((p) => p + 1)}
              >
                Next
              </Button>
            </div>
          </div>
        )}
      </div>

      <AlertDialog
        open={pendingDeactivate !== null}
        onOpenChange={(open) => {
          if (!open) {
            setPendingDeactivate(null)
            setDeactivateError(null)
          }
        }}
      >
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Deactivate user?</AlertDialogTitle>
            <AlertDialogDescription>
              This will deactivate <strong>{pendingDeactivate?.email}</strong> and revoke all their
              active sessions. They will not be able to log in until reactivated.
            </AlertDialogDescription>
          </AlertDialogHeader>
          {deactivateError && (
            <div className="rounded-md bg-destructive/10 px-3 py-2 text-sm text-destructive">
              {deactivateError}
            </div>
          )}
          <AlertDialogFooter>
            <AlertDialogCancel disabled={actionInProgress === pendingDeactivate?.id}>
              Cancel
            </AlertDialogCancel>
            <Button
              className="bg-destructive text-white hover:bg-destructive/90"
              disabled={actionInProgress === pendingDeactivate?.id}
              onClick={() => {
                if (pendingDeactivate) handleDeactivate(pendingDeactivate)
              }}
            >
              {actionInProgress === pendingDeactivate?.id ? (
                <svg className="h-3 w-3 animate-spin" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" aria-hidden="true">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                </svg>
              ) : 'Deactivate'}
            </Button>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </AppSidebar>
  )
}
