import { useEffect, useState } from 'react'
import { Search } from 'lucide-react'
import { toast } from 'sonner'
import { AppSidebar } from '@/components/app-sidebar'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import {
  AlertDialog,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog'
import { adminApi } from '@/api/admin'
import type { PaginationMeta } from '@/api/admin'
import type { AdminUser } from '@/types/auth'
import { getApiError } from '@/lib/utils'

const Spinner = ({ className = 'h-4 w-4' }: { className?: string }) => (
  <svg
    className={`animate-spin ${className}`}
    xmlns="http://www.w3.org/2000/svg"
    fill="none"
    viewBox="0 0 24 24"
    aria-hidden="true"
  >
    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
  </svg>
)

const roleBadge = (role: string) =>
  `inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ${
    role === 'admin' ? 'bg-purple-100 text-purple-800' : 'bg-gray-100 text-gray-700'
  }`

const verifiedBadge = (verified: boolean) =>
  `inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ${
    verified ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'
  }`

const statusBadge = (deactivated: boolean) =>
  `inline-flex items-center rounded-full px-2 py-0.5 text-xs font-medium ${
    deactivated ? 'bg-red-100 text-red-800' : 'bg-green-100 text-green-800'
  }`

export function UsersPage() {
  const [users, setUsers] = useState<AdminUser[]>([])
  const [meta, setMeta] = useState<PaginationMeta | null>(null)
  const [page, setPage] = useState(1)
  const [search, setSearch] = useState('')
  const [debouncedSearch, setDebouncedSearch] = useState('')
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [actionInProgress, setActionInProgress] = useState<string | null>(null)
  const [pendingDeactivate, setPendingDeactivate] = useState<AdminUser | null>(null)
  const [deactivateError, setDeactivateError] = useState<string | null>(null)

  useEffect(() => {
    const t = setTimeout(() => {
      setDebouncedSearch(search)
      setPage(1)
    }, 300)
    return () => clearTimeout(t)
  }, [search])

  function loadUsers(p = page, s = debouncedSearch) {
    setLoading(true)
    setError(null)
    adminApi
      .listUsers(p, 20, s)
      .then(({ data }) => {
        setUsers(data.users)
        setMeta(data.meta)
      })
      .catch((err: unknown) =>
        setError(getApiError(err, 'Failed to load users. Check your connection and try again.'))
      )
      .finally(() => setLoading(false))
  }

  useEffect(() => {
    loadUsers(page, debouncedSearch)
  }, [page, debouncedSearch])

  async function handleDeactivate(user: AdminUser) {
    setActionInProgress(user.id)
    setDeactivateError(null)
    try {
      const { data } = await adminApi.deactivateUser(user.id)
      setUsers((prev) => prev.map((u) => (u.id === user.id ? data.user : u)))
      toast.success(`${user.email} deactivated`)
      setPendingDeactivate(null)
    } catch (err: unknown) {
      setDeactivateError(getApiError(err, 'Failed to deactivate user'))
    } finally {
      setActionInProgress(null)
    }
  }

  async function handleActivate(user: AdminUser) {
    setActionInProgress(user.id)
    try {
      const { data } = await adminApi.activateUser(user.id)
      setUsers((prev) => prev.map((u) => (u.id === user.id ? data.user : u)))
      toast.success(`${user.email} activated`)
    } catch (err: unknown) {
      toast.error(getApiError(err, 'Failed to activate user'))
    } finally {
      setActionInProgress(null)
    }
  }

  const emptyState = (
    <div className="py-10 text-center text-muted-foreground">
      <p className="font-medium">{search ? 'No users match your search' : 'No users found'}</p>
      <p className="text-xs mt-1">
        {search ? 'Try a different search term.' : 'Registered users will appear here.'}
      </p>
    </div>
  )

  return (
    <AppSidebar>
      <div className="space-y-4 md:space-y-6">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div>
            <h2 className="text-xl font-bold tracking-tight md:text-2xl">Users</h2>
            <p className="text-sm text-muted-foreground">Manage platform user accounts</p>
          </div>
          <div className="relative w-full sm:w-64">
            <Search
              className="absolute left-2.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground"
              aria-hidden="true"
            />
            <Input
              type="search"
              placeholder="Search by email..."
              className="pl-8"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              aria-label="Search users"
            />
          </div>
        </div>

        {loading ? (
          <div aria-live="polite" className="flex items-center gap-2 text-sm text-muted-foreground">
            <Spinner />
            Loading users...
          </div>
        ) : error ? (
          <div className="flex items-center justify-between rounded-md border border-destructive/30 bg-destructive/10 px-4 py-3 text-sm text-destructive">
            <span>{error}</span>
            <Button size="sm" variant="outline" onClick={() => loadUsers(page)}>
              Retry
            </Button>
          </div>
        ) : (
          <>
            {/* Mobile: card list */}
            <div className="md:hidden space-y-3">
              {users.length === 0 ? (
                emptyState
              ) : (
                users.map((user) => (
                  <div key={user.id} className="rounded-md border p-4 space-y-3">
                    <div className="flex items-start justify-between gap-2">
                      <span className="font-mono text-xs break-all leading-relaxed">
                        {user.email}
                      </span>
                      <span className={statusBadge(user.deactivated)}>
                        {user.deactivated ? 'Deactivated' : 'Active'}
                      </span>
                    </div>
                    <div className="flex flex-wrap gap-2">
                      <span className={roleBadge(user.role)}>{user.role}</span>
                      <span className={verifiedBadge(user.email_verified)}>
                        {user.email_verified ? 'Verified' : 'Unverified'}
                      </span>
                      <span className="text-xs text-muted-foreground">
                        {new Date(user.created_at).toLocaleDateString('en-CA')}
                      </span>
                    </div>
                    {user.deactivated ? (
                      <Button
                        size="sm"
                        variant="outline"
                        className="w-full"
                        disabled={actionInProgress === user.id}
                        aria-label={`Activate ${user.email}`}
                        onClick={() => handleActivate(user)}
                      >
                        {actionInProgress === user.id ? <Spinner className="h-3 w-3" /> : 'Activate'}
                      </Button>
                    ) : (
                      <Button
