    const t = setTimeout(() => {
      setDebouncedSearch(search)
      setPage(1)
    }, 300)
    return () => clearTimeout(t)
  }, [search])

  function loadUsers(p = page, s = debouncedSearch) {
    setLoading(true)
    setError(null)
    adminApi
      .listUsers(p, 20, s)
      .then(({ data }) => {
        setUsers(data.users)
        setMeta(data.meta)
