const defaultMeta: PaginationMeta = { total: 2, page: 1, per_page: 20 }

function makeListResponse(users: AdminUser[], meta = defaultMeta) {
  return { data: { users, meta } }
}

function renderPage() {
  return render(
    <MemoryRouter>
      <UsersPage />
    </MemoryRouter>,
  )
}

// Both mobile card list and desktop table render in JSDOM (no CSS applied).
// Use getAllBy* for elements that appear in both views.
async function waitForLoad() {
  await waitFor(() => screen.getAllByText('user@test.com'))
}

async function waitForBanned() {
  await waitFor(() => screen.getAllByText('banned@test.com'))
}

describe('UsersPage', () => {
  beforeEach(() => {
    vi.clearAllMocks()
    mockAdminApi.listUsers.mockResolvedValue(makeListResponse([activeUser, deactivatedUser]))
    mockAdminApi.deactivateUser.mockResolvedValue({
      data: { message: 'ok', user: { ...activeUser, deactivated: true, deactivated_at: '2024-03-01' } },
    })
    mockAdminApi.activateUser.mockResolvedValue({
      data: { message: 'ok', user: { ...deactivatedUser, deactivated: false, deactivated_at: null } },
    })
  })

  describe('loading and error states', () => {
    it('shows loading spinner while fetching', () => {
      mockAdminApi.listUsers.mockReturnValueOnce(new Promise(() => {}))

      renderPage()

      expect(screen.getByText('Loading users...')).toBeInTheDocument()
    })

    it('renders user emails after load', async () => {
      renderPage()

      await waitForLoad()
      expect(screen.getAllByText('banned@test.com').length).toBeGreaterThan(0)
    })

    it('shows inline error banner when list users fails', async () => {
      mockAdminApi.listUsers.mockRejectedValueOnce(new Error('Network error'))

      renderPage()

      await waitFor(() =>
        expect(
          screen.getByText('Failed to load users. Check your connection and try again.'),
        ).toBeInTheDocument(),
      )
      expect(mockToast.error).not.toHaveBeenCalled()
    })

    it('shows permission denied message for 403 error', async () => {
      mockAdminApi.listUsers.mockRejectedValueOnce({ status: 403 })

      renderPage()

      await waitFor(() =>
        expect(screen.getByText('You do not have permission to perform this action.')).toBeInTheDocument(),
      )
    })

    it('shows server error message for 500 error', async () => {
      mockAdminApi.listUsers.mockRejectedValueOnce({ status: 500 })

      renderPage()

      await waitFor(() =>
        expect(screen.getByText('Server error. Please try again later.')).toBeInTheDocument(),
      )
    })

    it('retry button re-fetches users', async () => {
      mockAdminApi.listUsers.mockRejectedValueOnce(new Error('Network error'))
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([activeUser]))

      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByRole('button', { name: 'Retry' }))
      await user.click(screen.getByRole('button', { name: 'Retry' }))

      await waitFor(() => expect(screen.getAllByText('user@test.com').length).toBeGreaterThan(0))
      expect(mockAdminApi.listUsers).toHaveBeenCalledTimes(2)
    })
  })

  describe('table content', () => {
    it('shows Deactivate button for active users', async () => {
      renderPage()

      await waitForLoad()
      expect(screen.getAllByRole('button', { name: 'Deactivate user@test.com' }).length).toBeGreaterThan(0)
    })

    it('shows Activate button for deactivated users', async () => {
      renderPage()

      await waitForBanned()
      expect(screen.getAllByRole('button', { name: 'Activate banned@test.com' }).length).toBeGreaterThan(0)
    })

    it('shows "No users found" for empty list', async () => {
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([]))

      renderPage()

      await waitFor(() => expect(screen.getAllByText('No users found').length).toBeGreaterThan(0))
    })

    it('formats date as YYYY-MM-DD', async () => {
      renderPage()

      await waitForLoad()
      expect(screen.getAllByText('2024-01-15').length).toBeGreaterThan(0)
    })

    it('shows admin role badge in purple', async () => {
      const adminUser = { ...activeUser, role: 'admin' as const }
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([adminUser]))

      renderPage()

      await waitFor(() => screen.getAllByText('user@test.com'))
      const badges = screen.getAllByText('admin')
      expect(badges.some((el) => el.className.includes('purple'))).toBe(true)
    })

    it('shows verified badge in green for verified users', async () => {
      renderPage()

      await waitForLoad()
      const badges = screen.getAllByText('Verified')
      const badge = badges.find((el) => el.tagName === 'SPAN')!
      expect(badge.className).toContain('green')
    })

    it('shows unverified badge for unverified users', async () => {
      renderPage()

      await waitForBanned()
      expect(screen.getAllByText('Unverified').length).toBeGreaterThan(0)
    })
  })

  describe('activate action', () => {
    it('calls activateUser and shows success toast', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitForBanned()
      await user.click(screen.getAllByRole('button', { name: 'Activate banned@test.com' })[0])

      await waitFor(() => expect(mockAdminApi.activateUser).toHaveBeenCalledWith('2'))
      expect(mockToast.success).toHaveBeenCalledWith('banned@test.com activated')
    })

    it('shows error toast when activate fails with API error', async () => {
      mockAdminApi.activateUser.mockRejectedValueOnce({ error: 'User not found' })
      const user = userEvent.setup()
      renderPage()

      await waitForBanned()
      await user.click(screen.getAllByRole('button', { name: 'Activate banned@test.com' })[0])

      await waitFor(() => expect(mockToast.error).toHaveBeenCalledWith('User not found'))
    })

    it('shows generic error toast when activate fails without message', async () => {
      mockAdminApi.activateUser.mockRejectedValueOnce(new Error())
      const user = userEvent.setup()
      renderPage()

      await waitForBanned()
      await user.click(screen.getAllByRole('button', { name: 'Activate banned@test.com' })[0])

      await waitFor(() => expect(mockToast.error).toHaveBeenCalledWith('Failed to activate user'))
    })

    it('disables activate button while in progress', async () => {
      let resolveActivate!: () => void
      mockAdminApi.activateUser.mockReturnValueOnce(
        new Promise<{ data: { message: string; user: AdminUser } }>((res) => {
          resolveActivate = () => res({ data: { message: 'ok', user: { ...deactivatedUser, deactivated: false, deactivated_at: null } } })
        }),
      )
      const user = userEvent.setup()
      renderPage()

      await waitForBanned()
      await user.click(screen.getAllByRole('button', { name: 'Activate banned@test.com' })[0])

      await waitFor(() => {
        const btn = document.querySelector('button[aria-label="Activate banned@test.com"]')
        expect(btn).toBeDisabled()
      })

      resolveActivate()
      await waitFor(() =>
        expect(screen.getAllByRole('button', { name: 'Deactivate banned@test.com' }).length).toBeGreaterThan(0),
      )
    })
  })

  describe('deactivate confirmation dialog', () => {
    it('opens dialog when Deactivate button clicked', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitForLoad()
      await user.click(screen.getAllByRole('button', { name: 'Deactivate user@test.com' })[0])

      expect(screen.getByText('Deactivate user?')).toBeInTheDocument()
    })

    it('dialog shows the user email', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitForLoad()
      await user.click(screen.getAllByRole('button', { name: 'Deactivate user@test.com' })[0])

      await waitFor(() => {
        const dialog = screen.getByRole('alertdialog')
        expect(within(dialog).getByText('user@test.com')).toBeInTheDocument()
      })
    })

    it('Cancel closes dialog without calling API', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitForLoad()
      await user.click(screen.getAllByRole('button', { name: 'Deactivate user@test.com' })[0])
      await waitFor(() => screen.getByText('Deactivate user?'))

      await user.click(screen.getByRole('button', { name: 'Cancel' }))

      await waitFor(() => expect(screen.queryByText('Deactivate user?')).not.toBeInTheDocument())
      expect(mockAdminApi.deactivateUser).not.toHaveBeenCalled()
    })

    it('Deactivate button in dialog calls deactivateUser', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitForLoad()
      await user.click(screen.getAllByRole('button', { name: 'Deactivate user@test.com' })[0])
      await waitFor(() => screen.getByText('Deactivate user?'))

      await user.click(screen.getByRole('button', { name: 'Deactivate' }))

      await waitFor(() => expect(mockAdminApi.deactivateUser).toHaveBeenCalledWith('1'))
    })

    it('dialog closes and shows success toast on successful deactivate', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitForLoad()
      await user.click(screen.getAllByRole('button', { name: 'Deactivate user@test.com' })[0])
      await waitFor(() => screen.getByText('Deactivate user?'))
      await user.click(screen.getByRole('button', { name: 'Deactivate' }))

      await waitFor(() => expect(screen.queryByText('Deactivate user?')).not.toBeInTheDocument())
      expect(mockToast.success).toHaveBeenCalledWith('user@test.com deactivated')
    })

    it('dialog stays open and shows inline error on deactivate failure', async () => {
      mockAdminApi.deactivateUser.mockRejectedValueOnce({ error: 'Cannot deactivate admin' })
      const user = userEvent.setup()
      renderPage()

      await waitForLoad()
      await user.click(screen.getAllByRole('button', { name: 'Deactivate user@test.com' })[0])
      await waitFor(() => screen.getByText('Deactivate user?'))
      await user.click(screen.getByRole('button', { name: 'Deactivate' }))

      await waitFor(() => expect(screen.getByText('Cannot deactivate admin')).toBeInTheDocument())
      expect(screen.getByText('Deactivate user?')).toBeInTheDocument()
      expect(mockToast.error).not.toHaveBeenCalled()
    })

    it('dialog shows generic error when deactivate fails without message', async () => {
      mockAdminApi.deactivateUser.mockRejectedValueOnce(new Error())
      const user = userEvent.setup()
      renderPage()

      await waitForLoad()
      await user.click(screen.getAllByRole('button', { name: 'Deactivate user@test.com' })[0])
      await waitFor(() => screen.getByText('Deactivate user?'))
      await user.click(screen.getByRole('button', { name: 'Deactivate' }))

      await waitFor(() => expect(screen.getByText('Failed to deactivate user')).toBeInTheDocument())
    })

    it('dialog buttons disabled while deactivation in progress', async () => {
      let resolveDeactivate!: () => void
      mockAdminApi.deactivateUser.mockReturnValueOnce(
        new Promise<{ data: { message: string; user: AdminUser } }>((res) => {
          resolveDeactivate = () =>
            res({ data: { message: 'ok', user: { ...activeUser, deactivated: true, deactivated_at: '2024-03-01' } } })
        }),
      )
      const user = userEvent.setup()
      renderPage()

      await waitForLoad()
      await user.click(screen.getAllByRole('button', { name: 'Deactivate user@test.com' })[0])
      await waitFor(() => screen.getByText('Deactivate user?'))
      await user.click(screen.getByRole('button', { name: 'Deactivate' }))

      await waitFor(() =>
        expect(screen.getByRole('button', { name: 'Cancel' })).toBeDisabled(),
      )

      resolveDeactivate()
    })

    it('updates user row to Activate button after successful deactivate', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitForLoad()
      await user.click(screen.getAllByRole('button', { name: 'Deactivate user@test.com' })[0])
      await waitFor(() => screen.getByText('Deactivate user?'))
      await user.click(screen.getByRole('button', { name: 'Deactivate' }))

      // Both mobile cards and table render, so 2 views × 2 deactivated users = 4 Activate buttons
      await waitFor(() =>
        expect(screen.getAllByRole('button', { name: /^Activate/ })).toHaveLength(4),
      )
    })

    it('clears error when dialog is closed and reopened', async () => {
      mockAdminApi.deactivateUser
        .mockRejectedValueOnce({ error: 'Server error' })
        .mockResolvedValueOnce({
          data: { message: 'ok', user: { ...activeUser, deactivated: true, deactivated_at: '2024-03-01' } },
        })
      const user = userEvent.setup()
      renderPage()

      await waitForLoad()

      await user.click(screen.getAllByRole('button', { name: 'Deactivate user@test.com' })[0])
      await waitFor(() => screen.getByText('Deactivate user?'))
      await user.click(screen.getByRole('button', { name: 'Deactivate' }))
      await waitFor(() => screen.getByText('Server error'))

      await user.click(screen.getByRole('button', { name: 'Cancel' }))
      await waitFor(() => expect(screen.queryByText('Deactivate user?')).not.toBeInTheDocument())

      await user.click(screen.getAllByRole('button', { name: 'Deactivate user@test.com' })[0])
      await waitFor(() => screen.getByText('Deactivate user?'))

      expect(screen.queryByText('Server error')).not.toBeInTheDocument()
    })
  })

  describe('search', () => {
    it('renders search input', async () => {
      renderPage()

      await waitForLoad()
      expect(screen.getByRole('searchbox', { name: 'Search users' })).toBeInTheDocument()
    })

    it('calls listUsers with search param after debounce', async () => {
      mockAdminApi.listUsers.mockResolvedValue(makeListResponse([]))
      const user = userEvent.setup()
      renderPage()

      await waitFor(() => expect(mockAdminApi.listUsers).toHaveBeenCalledTimes(1))

      await user.type(screen.getByRole('searchbox', { name: 'Search users' }), 'alice')

      await waitFor(
        () => expect(mockAdminApi.listUsers).toHaveBeenCalledWith(1, 20, 'alice'),
        { timeout: 500 },
      )
    })

    it('does not call listUsers immediately on each keystroke', async () => {
      const user = userEvent.setup()
      renderPage()

      await waitFor(() => expect(mockAdminApi.listUsers).toHaveBeenCalledTimes(1))
      mockAdminApi.listUsers.mockClear()

      const searchInput = screen.getByRole('searchbox', { name: 'Search users' })
      await user.type(searchInput, 'ab')

      await waitFor(() => expect(mockAdminApi.listUsers).toHaveBeenCalledTimes(1), { timeout: 500 })
    })

    it('shows "No users match your search" when search returns empty', async () => {
      mockAdminApi.listUsers.mockResolvedValue(makeListResponse([]))
      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByRole('searchbox', { name: 'Search users' }))
      await user.type(screen.getByRole('searchbox', { name: 'Search users' }), 'xyz')

      await waitFor(
        () => expect(screen.getAllByText('No users match your search').length).toBeGreaterThan(0),
        { timeout: 500 },
      )
    })

    it('resets to page 1 when search changes', async () => {
      const page1Meta: PaginationMeta = { total: 50, page: 1, per_page: 20 }
      const page2Meta: PaginationMeta = { total: 50, page: 2, per_page: 20 }
      mockAdminApi.listUsers
        .mockResolvedValueOnce(makeListResponse([activeUser], page1Meta))
        .mockResolvedValueOnce(makeListResponse([activeUser], page2Meta))
        .mockResolvedValue(makeListResponse([activeUser]))

      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByRole('button', { name: 'Next' }))
      await user.click(screen.getByRole('button', { name: 'Next' }))
      await waitFor(() => expect(mockAdminApi.listUsers).toHaveBeenCalledWith(2, 20, ''))

      await user.type(screen.getByRole('searchbox', { name: 'Search users' }), 'a')
      await waitFor(
        () => expect(mockAdminApi.listUsers).toHaveBeenCalledWith(1, 20, 'a'),
        { timeout: 500 },
      )
    })
  })

  describe('pagination', () => {
    const paginatedMeta: PaginationMeta = { total: 50, page: 1, per_page: 20 }

    it('hides pagination when all users fit on one page', async () => {
      renderPage()

      await waitForLoad()
      expect(screen.queryByRole('button', { name: 'Next' })).not.toBeInTheDocument()
      expect(screen.queryByRole('button', { name: 'Previous' })).not.toBeInTheDocument()
    })

    it('shows pagination controls when total > per_page', async () => {
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([activeUser], paginatedMeta))

      renderPage()

      await waitFor(() => screen.getByRole('button', { name: 'Next' }))
      expect(screen.getByRole('button', { name: 'Previous' })).toBeInTheDocument()
    })

    it('shows correct range and total label', async () => {
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([activeUser], paginatedMeta))

      renderPage()

      await waitFor(() => screen.getByText('1–20 of 50 users'))
    })

    it('Previous button disabled on first page', async () => {
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([activeUser], paginatedMeta))

      renderPage()

      await waitFor(() => screen.getByRole('button', { name: 'Previous' }))
      expect(screen.getByRole('button', { name: 'Previous' })).toBeDisabled()
    })

    it('Next button enabled on first page', async () => {
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([activeUser], paginatedMeta))

      renderPage()

      await waitFor(() => screen.getByRole('button', { name: 'Next' }))
      expect(screen.getByRole('button', { name: 'Next' })).not.toBeDisabled()
    })

    it('clicking Next fetches next page', async () => {
      mockAdminApi.listUsers.mockResolvedValue(makeListResponse([activeUser], paginatedMeta))

      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByRole('button', { name: 'Next' }))
      await user.click(screen.getByRole('button', { name: 'Next' }))

      await waitFor(() => expect(mockAdminApi.listUsers).toHaveBeenCalledWith(2, 20, ''))
    })

    it('clicking Previous fetches previous page', async () => {
      const page2Meta: PaginationMeta = { total: 50, page: 2, per_page: 20 }
      mockAdminApi.listUsers
        .mockResolvedValueOnce(makeListResponse([activeUser], paginatedMeta))
        .mockResolvedValueOnce(makeListResponse([activeUser], page2Meta))
        .mockResolvedValueOnce(makeListResponse([activeUser], paginatedMeta))

      const user = userEvent.setup()
      renderPage()

      await waitFor(() => screen.getByRole('button', { name: 'Next' }))
      await user.click(screen.getByRole('button', { name: 'Next' }))
      await waitFor(() => expect(mockAdminApi.listUsers).toHaveBeenCalledWith(2, 20, ''))

      await user.click(screen.getByRole('button', { name: 'Previous' }))
      await waitFor(() => expect(mockAdminApi.listUsers).toHaveBeenCalledWith(1, 20, ''))
    })

    it('Next button disabled on last page', async () => {
      const lastPageMeta: PaginationMeta = { total: 40, page: 2, per_page: 20 }
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([activeUser], lastPageMeta))

      renderPage()

      await waitFor(() => screen.getByRole('button', { name: 'Next' }))
      expect(screen.getByRole('button', { name: 'Next' })).toBeDisabled()
    })

    it('shows current page of total pages', async () => {
      mockAdminApi.listUsers.mockResolvedValueOnce(makeListResponse([activeUser], paginatedMeta))

      renderPage()

      await waitFor(() => screen.getByText('Page 1 of 3'))
    })
  })
})

