def index
  page, per_page = pagination_params
  scope = AuthCredential.order(created_at: :desc)
  scope = scope.where('email ILIKE ?', "%#{params[:search]}%") if params[:search].present?
  render json: {
    users: scope.offset((page - 1) * per_page).limit(per_page).map { |u| admin_user_payload(u) },
    meta: { total: scope.count, page: page, per_page: per_page }
  }
end

